class Fenw(private val n: Int) {
    private val tree = LongArray(n + 1)

    fun update(index: Int, delta: Long) {
        var i = index + 1
        while (i <= n) {
            tree[i] += delta
            i += i and -i
        }
    }

    private fun prefix(i: Int): Long {
        if (i < 0) return 0
        var idx = i + 1
        var s = 0L
        while (idx > 0) {
            s += tree[idx]
            idx -= idx and -idx
        }
        return s
    }

    fun query(l: Int, r: Int): Long {
        if (l > r) return 0
        return prefix(r) - prefix(l - 1)
    }
}

fun computeDepth(x: Long): Int {
    if (x == 1L) return 0
    var cur = x
    var d = 0
    while (cur != 1L) {
        cur = java.lang.Long.bitCount(cur).toLong()
        d++
    }
    return d
}

fun solve(nums: Array<Long>, queries: Array<Array<Long>>): Array<Long> {
    val n = nums.size
    val depthArr = IntArray(n)
    for (i in nums.indices) {
        depthArr[i] = computeDepth(nums[i])
    }

    val trees = Array(6) { Fenw(n) }
    for (i in 0 until n) {
        val d = depthArr[i]
        if (d <= 5) {
            trees[d].update(i, 1)
        }
    }

    val ans = mutableListOf<Long>()
    for (q in queries) {
        if (q[0] == 1L) {
            val l = q[1].toInt()
            val r = q[2].toInt()
            val k = q[3].toInt()
            if (k > 5) {
                ans.add(0L)
            } else {
                ans.add(trees[k].query(l, r))
            }
        } else if (q[0] == 2L) {
            val idx = q[1].toInt()
            val newVal = q[2]
            val newDepth = computeDepth(newVal)
            val oldDepth = depthArr[idx]
            if (oldDepth <= 5) {
                trees[oldDepth].update(idx, -1)
            }
            if (newDepth <= 5) {
                trees[newDepth].update(idx, 1)
            }
            depthArr[idx] = newDepth
        }
    }
    return ans.toTypedArray()
}
