fun solve(nums: Array<Long>, queries: Array<Array<Long>>): Array<Long> {
    val n = nums.size

    fun getDepth(x: Long): Int {
        if (x == 1L) return 0
        var cur = x
        var cnt = 0
        while (cur != 1L) {
            cur = cur.countOneBits().toLong()
            cnt++
        }
        return cnt
    }

    fun update(tree: LongArray, index: Int, delta: Long) {
        var i = index + 1
        val size = tree.size - 1
        while (i <= size) {
            tree[i] += delta
            i += i and -i
        }
    }

    fun prefixQuery(tree: LongArray, index: Int): Long {
        if (index < 0) return 0L
        var i = index + 1
        var s = 0L
        while (i > 0) {
            s += tree[i]
            i -= i and -i
        }
        return s
    }

    fun rangeQuery(tree: LongArray, l: Int, r: Int): Long {
        if (l > r) return 0L
        return prefixQuery(tree, r) - prefixQuery(tree, l - 1)
    }

    val fenwTrees = Array(6) { LongArray(n + 1) }

    val depthArr = IntArray(n)
    for (i in 0 until n) {
        depthArr[i] = getDepth(nums[i])
        if (depthArr[i] in 0..5) {
            update(fenwTrees[depthArr[i]], i, 1L)
        }
    }

    val ansList = mutableListOf<Long>()
    for (q in queries) {
        when (q[0]) {
            1L -> {
                val l = q[1].toInt()
                val r = q[2].toInt()
                val k = q[3].toInt()
                val result = if (k in 0..5) rangeQuery(fenwTrees[k], l, r) else 0L
                ansList.add(result)
            }
            2L -> {
                val idx = q[1].toInt()
                val newVal = q[2]
                val oldDepth = depthArr[idx]
                val newDepth = getDepth(newVal)
                depthArr[idx] = newDepth
                if (oldDepth in 0..5) {
                    update(fenwTrees[oldDepth], idx, -1L)
                }
                if (newDepth in 0..5) {
                    update(fenwTrees[newDepth], idx, 1L)
                }
            }
        }
    }
    return ansList.toTypedArray()
}
