fun solve(nums: Array<Long>, queries: Array<Array<Long>>): Array<Long> {
    val dpSmall = IntArray(61)
    dpSmall[1] = 0
    for (i in 2..60) {
        val pop = Integer.bitCount(i)
        dpSmall[i] = 1 + dpSmall[pop]
    }

    fun computeDepth(x: Long): Int {
        if (x == 1L) return 0
        val pop = java.lang.Long.bitCount(x)
        return 1 + dpSmall[pop]
    }

    val n = nums.size
    val depths = IntArray(n)
    for (i in 0 until n) {
        depths[i] = computeDepth(nums[i])
    }

    val fenwTrees = Array(6) { LongArray(n + 1) }

    fun update(treeIndex: Int, idx: Int, delta: Long) {
        var index = idx + 1
        while (index <= n) {
            fenwTrees[treeIndex][index] = fenwTrees[treeIndex][index] + delta
            index += index and -index
        }
    }

    fun query(treeIndex: Int, idx: Int): Long {
        var index = idx + 1
        var s = 0L
        while (index > 0) {
            s += fenwTrees[treeIndex][index]
            index -= index and -index
        }
        return s
    }

    fun rangeSum(treeIndex: Int, l: Int, r: Int): Long {
        if (l > r) return 0
        if (l == 0) {
            return query(treeIndex, r)
        }
        return query(treeIndex, r) - query(treeIndex, l - 1)
    }

    for (i in 0 until n) {
        val d = depths[i]
        if (d in 0..5) {
            update(d, i, 1)
        }
    }

    val ansList = mutableListOf<Long>()
    for (q in queries) {
        if (q[0] == 1L) {
            val l = q[1].toInt()
            val r = q[2].toInt()
            val k = q[3].toInt()
            if (k in 0..5) {
                ansList.add(rangeSum(k, l, r))
            } else {
                ansList.add(0)
            }
        } else if (q[0] == 2L) {
            val idx = q[1].toInt()
            val newVal = q[2]
            val newDepth = computeDepth(newVal)
            val oldDepth = depths[idx]
            if (oldDepth != newDepth) {
                if (oldDepth in 0..5) {
                    update(oldDepth, idx, -1)
                }
                if (newDepth in 0..5) {
                    update(newDepth, idx, 1)
                }
                depths[idx] = newDepth
            }
        }
    }

    return ansList.toTypedArray()
}
