fun solve(nums: Array<Long>, queries: Array<Array<Long>>): Array<Long> {
    val maxSize = 60
    val depthArray = IntArray(maxSize + 1)
    depthArray[1] = 0
    for (i in 2..maxSize) {
        val pop = Integer.bitCount(i)
        depthArray[i] = 1 + depthArray[pop]
    }

    fun getDepth(x: Long): Int {
        if (x == 1L) return 0
        if (x <= maxSize) {
            return depthArray[x.toInt()]
        }
        val pop = java.lang.Long.bitCount(x)
        return 1 + depthArray[pop]
    }

    val n = nums.size
    val currentDepth = IntArray(n) { i -> getDepth(nums[i]) }

    class FenwTree(private val size: Int) {
        private val tree = LongArray(size + 1) { 0 }

        fun update(i: Int, v: Long) {
            var idx = i + 1
            while (idx <= size) {
                tree[idx] = tree[idx] + v
                idx += idx and -idx
            }
        }

        private fun queryPrefix(i: Int): Long {
            if (i < 0) return 0L
            var idx = i + 1
            var sum = 0L
            while (idx > 0) {
                sum += tree[idx]
                idx -= idx and -idx
            }
            return sum
        }

        fun query(l: Int, r: Int): Long {
            return queryPrefix(r) - queryPrefix(l - 1)
        }
    }

    val fenwTrees = Array(6) { FenwTree(n) }

    for (i in 0 until n) {
        val d = currentDepth[i]
        if (d in 0..5) {
            fenwTrees[d].update(i, 1)
        }
    }

    val ansList = mutableListOf<Long>()
    for (q in queries) {
        if (q[0] == 1L) {
            val l = q[1].toInt()
            val r = q[2].toInt()
            val k = q[3].toInt()
            if (k in 0..5) {
                ansList.add(fenwTrees[k].query(l, r))
            } else {
                ansList.add(0)
            }
        } else {
            val idx = q[1].toInt()
            val value = q[2]
            val oldDepth = currentDepth[idx]
            val newDepth = getDepth(value)
            if (oldDepth in 0..5) {
                fenwTrees[oldDepth].update(idx, -1)
            }
            if (newDepth in 0..5) {
                fenwTrees[newDepth].update(idx, 1)
            }
            currentDepth[idx] = newDepth
        }
    }

    return ansList.toTypedArray()
}
```

